class AvoidLosingExceptionInformation {
    public void showBug() {
        try {
            throw new Exception("This is a test exception");
        } catch (Exception se) {
            if (true) {
                se.getMessage();    // should raise flag
            } else {
                se.getLocalizedMessage();    // should raise flag
            }
        }
    }
}

