import net.sourceforge.pmd.lang.java.rule.errorprone.checkreturnvalue.HasAnnotatedMethod;

public class Foo {
    public void bar(HasAnnotatedMethod x) {
        x.annotatedMethod();  // bad

        System.out.println(x.annotatedMethod());  // good
    }
}

import net.sourceforge.pmd.lang.java.rule.errorprone.checkreturnvalue.AnnotatedClass;

public class Foo {
    public void bar(AnnotatedClass x) {
        x.shouldBeChecked();  // bad

        System.out.println(x.shouldBeChecked());  // good

        x.doesNotNeedToBeChecked();  // good, because the method is annotated with @CanIgnoreReturnValue
    }
}

import net.sourceforge.pmd.lang.java.rule.errorprone.checkreturnvalue.annotatedpackage.ClassInAnnotatedPackage;

public class Foo {
    public void bar(ClassInAnnotatedPackage x) {
        x.shouldBeChecked();  // bad

        System.out.println(x.shouldBeChecked());  // good

        x.doesNotNeedToBeChecked();  // good, because the method is annotated with @CanIgnoreReturnValue
    }
}

import net.sourceforge.pmd.lang.java.rule.errorprone.checkreturnvalue.ClassWithUnrelatedAnnotation;

public class Foo {
    public void bar(ClassWithUnrelatedAnnotation x) {
        x.doesNotNeedToBeChecked();  // good
    }
}
